// Build the date list to scrape.
// Manual trigger payload may include { backfillDates: ['YYYY-MM-DD', ...] } —
// in that case we backfill those dates. Otherwise we scrape yesterday
// (CST), which is when the day's billable leads are stable.
const input = $input.first()?.json ?? {};
const manualDates = Array.isArray(input.backfillDates)
  ? input.backfillDates.filter((d) => /^\d{4}-\d{2}-\d{2}$/.test(d))
  : [];

function yesterdayCST() {
  const central = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
  const [y, m, d] = central.split('-').map(Number);
  const dt = new Date(y, m - 1, d);
  dt.setDate(dt.getDate() - 1);
  // Skip weekends back to last weekday.
  while (dt.getDay() === 0 || dt.getDay() === 6) dt.setDate(dt.getDate() - 1);
  return dt.getFullYear() + '-' + String(dt.getMonth() + 1).padStart(2, '0') + '-' + String(dt.getDate()).padStart(2, '0');
}

const dates = manualDates.length > 0 ? manualDates : [yesterdayCST()];
return [{ json: { dates, isBackfill: manualDates.length > 0 } }];

// Fetch active roster + aliases from Supabase. Build:
//   - targetAgents: canonical names of all active agents (filter at the actor)
//   - nameAliases:  ICD display name -> canonical ROLI name
//                   (i.e. agent_name_aliases.crm_name -> canonical_name)
const ctx = $input.first().json;
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_PROJECT.supabase.co/rest/v1';
const hdr = { apikey };

const [roster, aliases] = await Promise.all([
  this.helpers.httpRequest({ method: 'GET', url: base + '/agents?select=name,is_active&is_active=eq.true', headers: hdr, json: true }),
  this.helpers.httpRequest({ method: 'GET', url: base + '/agent_name_aliases?select=canonical_name,crm_name', headers: hdr, json: true })
]);

if (!roster || roster.length === 0) {
  return [{ json: { error: true, message: 'No active agents found in Supabase', ...ctx } }];
}

const targetAgents = roster.map((a) => a.name);

// Build inverse alias map: ICD display name -> canonical ROLI name.
// Agents in the roster whose ICD display name happens to equal their canonical
// name don't need an entry (the actor falls through to identity).
const nameAliases = {};
for (const a of (aliases || [])) {
  if (a.crm_name && a.canonical_name && a.crm_name !== a.canonical_name) {
    nameAliases[a.crm_name] = a.canonical_name;
  }
}

return [{
  json: {
    ...ctx,
    agentCount: roster.length,
    targetAgents,
    nameAliases,
    apifyBody: JSON.stringify({
      icdUsername: 'YOUR_ICD_USERNAME',
      icdPassword: 'YOUR_ICD_PASSWORD',
      agencyId: '1428',
      backfillDates: ctx.dates,
      targetAgents,
      nameAliases,
      requestDelay: 1500
    })
  }
}];

// Pull the dataset from the Apify run, parse, and split each
// per-date icd_calls_report item into its own n8n item so the
// downstream HTTP node can fan out to ingest-daily-scrape once
// per date.
const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';
if (!datasetId) {
  return [{ json: { error: true, message: 'No defaultDatasetId. runId=' + runId } }];
}
const token = 'YOUR_APIFY_TOKEN';
const url = `https://api.apify.com/v2/datasets/${datasetId}/items?token=${token}`;
let items;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET',
      url,
      encoding: 'utf-8',
      timeout: 60000,
      headers: { Accept: 'application/json' },
    });
    items = typeof raw === 'string' ? JSON.parse(raw) : raw;
    if (Array.isArray(items) && items.length > 0) break;
  } catch (err) {
    if (attempt === 3) throw err;
    await new Promise((r) => setTimeout(r, 5000));
  }
}
if (!items || !Array.isArray(items) || items.length === 0) {
  return [{ json: { error: true, message: 'Dataset empty', datasetId, runId } }];
}

const out = [];
for (const item of items) {
  if (item._type === 'icd_calls_report' && Array.isArray(item.agents)) {
    out.push({
      json: {
        scrape_date: item.scrape_date,
        agency_id: item.agency_id,
        agent_count: item.agents.length,
        unmatched: (item.unmatched_agents || []).length,
        // Build the ingest payload here so the next node just forwards it.
        // Pass through ICD-sourced RPA fields:
        //   queue_minutes        — Time Spent In Queue
        //   inbound_talk_minutes — talk_minutes (ICD = purely inbound)
        //   avg_wait_minutes     — Avg Wait Time (operational signal)
        ingestBody: JSON.stringify({
          mode: 'ib_leads_only',
          scrape_date: item.scrape_date,
          agents: item.agents.map((a) => ({
            agent_name: a.agent_name,
            ib_leads_delivered: a.billable_leads,
            queue_minutes: a.queue_minutes ?? 0,
            inbound_talk_minutes: a.talk_minutes ?? 0,
            avg_wait_minutes: a.avg_wait_minutes ?? 0,
          })),
        }),
      },
    });
  } else if (item._type === 'icd_calls_report_error') {
    out.push({ json: { error: true, scrape_date: item.scrape_date, message: item.error } });
  }
}
if (out.length === 0) return [{ json: { error: true, message: 'No icd_calls_report items in dataset', datasetId, runId } }];
return out;

// Aggregate ingest responses and emit a single Slack-friendly summary.
// Runs once per workflow execution (after all per-date ingests complete).
const all = $input.all().map((i) => i.json);
const totalDates = all.length;
const ok = all.filter((r) => r.success !== false && !r.error);
const failed = all.filter((r) => r.success === false || r.error);
const alias = ok.reduce((s, r) => s + (r.alias_resolved || 0), 0);
const updated = ok.reduce((s, r) => s + (r.ib_leads_only_updated || 0), 0);
const inserted = ok.reduce((s, r) => s + (r.ib_leads_only_inserted || 0), 0);
const dates = ok.map((r) => r.scrape_date).sort();
const dateRange = dates.length > 0 ? `${dates[0]} → ${dates[dates.length - 1]}` : 'none';
const text = `:bar_chart: ICD Billable Leads sync — ${dateRange}\n` +
  `· dates: ${totalDates} (${ok.length} ok, ${failed.length} failed)\n` +
  `· rows updated: ${updated} · rows inserted: ${inserted} · alias resolved: ${alias}` +
  (failed.length > 0 ? `\n· :rotating_light: failures: ${failed.map((f) => f.scrape_date || 'unknown').join(', ')}` : '');
return [{ json: { text } }];
